import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate, Link } from 'react-router-dom';

function LoginPage({ setIsAuthenticated, setUsername }) {
  const [username, setUsernameState] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    
    try {
      const response = await axios.post('http://localhost:8000/api/token/', {
        username: username,
        password: password
      });
      
      localStorage.setItem('access', response.data.access);
      localStorage.setItem('refresh', response.data.refresh);
      localStorage.setItem('username', username);
      
      if (setIsAuthenticated) setIsAuthenticated(true);
      if (setUsername) setUsername(username);
      
      navigate('/');
    } catch (err) {
      setError('Неверное имя пользователя или пароль');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fade-in" style={{
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '80vh'
    }}>
      <form onSubmit={handleSubmit} style={{
        backgroundColor: 'var(--bg-secondary)',
        padding: '40px',
        borderRadius: 24,
        width: '100%',
        maxWidth: 440,
        border: '1px solid var(--border)'
      }}>
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🎬</div>
          <h2 style={{ color: 'var(--text-primary)', fontSize: 28, marginBottom: 8 }}>Добро пожаловать</h2>
          <p style={{ color: 'var(--text-secondary)' }}>Войдите в свой аккаунт</p>
        </div>
        
        {error && (
          <div style={{
            backgroundColor: 'rgba(255,0,0,0.1)',
            color: 'var(--accent)',
            padding: 12,
            borderRadius: 12,
            marginBottom: 20,
            textAlign: 'center',
            fontSize: 14
          }}>
            {error}
          </div>
        )}
        
        <input
          type="text"
          placeholder="Имя пользователя"
          value={username}
          onChange={(e) => setUsernameState(e.target.value)}
          required
          style={{
            width: '100%',
            padding: '14px 16px',
            marginBottom: 16,
            backgroundColor: 'var(--bg-card)',
            border: '1px solid var(--border)',
            borderRadius: 12,
            color: 'var(--text-primary)',
            fontSize: 16,
            transition: 'var(--transition)'
          }}
          onFocus={(e) => e.target.style.borderColor = 'var(--accent)'}
          onBlur={(e) => e.target.style.borderColor = 'var(--border)'}
        />
        
        <input
          type="password"
          placeholder="Пароль"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={{
            width: '100%',
            padding: '14px 16px',
            marginBottom: 24,
            backgroundColor: 'var(--bg-card)',
            border: '1px solid var(--border)',
            borderRadius: 12,
            color: 'var(--text-primary)',
            fontSize: 16,
            transition: 'var(--transition)'
          }}
          onFocus={(e) => e.target.style.borderColor = 'var(--accent)'}
          onBlur={(e) => e.target.style.borderColor = 'var(--border)'}
        />
        
        <button
          type="submit"
          disabled={loading}
          style={{
            width: '100%',
            padding: '14px',
            backgroundColor: loading ? 'var(--text-secondary)' : 'var(--accent)',
            color: 'white',
            border: 'none',
            borderRadius: 12,
            fontSize: 16,
            fontWeight: 600,
            cursor: loading ? 'not-allowed' : 'pointer',
            transition: 'var(--transition)'
          }}
        >
          {loading ? 'Вход...' : 'Войти'}
        </button>
        
        <p style={{ color: 'var(--text-secondary)', textAlign: 'center', marginTop: 24 }}>
          Нет аккаунта?{' '}
          <Link to="/register" style={{ color: 'var(--accent)', textDecoration: 'none', fontWeight: 500 }}>
            Зарегистрируйтесь
          </Link>
        </p>
      </form>
    </div>
  );
}

export default LoginPage;
